# Shape class hierarchy with inheritance and interface implementation
from types import Point2D, Dimension, ColorType, ShapeCategory
from interfaces import IDrawable, IMeasurable, IColorable

@abstract
class Shape(IMeasurable, IColorable):
    center: Point2D
    category: ShapeCategory

    def __init__(self, c: Point2D, cat: ShapeCategory):
        self.center = c
        self.category = cat

    @virtual
    def describe(self) -> str:
        return "Shape"

    @abstract
    def get_color_type(self) -> ColorType:
        pass

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, center: Point2D, r: float):
        super().__init__(center, ShapeCategory.CIRCLE)
        self.radius = r

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return f"Circle(r={self.radius})"

    @override
    def get_color_type(self) -> ColorType:
        return ColorType.PRIMARY

    def draw(self) -> str:
        return f"Drawing circle at ({self.center.x}, {self.center.y})"

class Rectangle(Shape, IDrawable):
    dim: Dimension

    def __init__(self, center: Point2D, d: Dimension):
        super().__init__(center, ShapeCategory.RECTANGLE)
        self.dim = d

    def area(self) -> float:
        return self.dim.width * self.dim.height

    def perimeter(self) -> float:
        return 2.0 * (self.dim.width + self.dim.height)

    @override
    def describe(self) -> str:
        return f"Rectangle({self.dim.width}x{self.dim.height})"

    @override
    def get_color_type(self) -> ColorType:
        return ColorType.SECONDARY

    def draw(self) -> str:
        return f"Drawing rectangle at ({self.center.x}, {self.center.y})"
